// Input validation helpers
function validatePositiveInt(value, fieldName) {
  const parsed = parseInt(value, 10);
  if (!Number.isFinite(parsed) || parsed < 1) {
    throw new Error(`Invalid ${fieldName}: must be a positive integer.`);
  }
  return parsed;
}

function validateStringInput(value, fieldName, maxLength = 255) {
  if (typeof value !== 'string') {
    throw new Error(`Invalid ${fieldName}: must be a string.`);
  }
  const trimmed = value.trim();
  if (trimmed.length === 0) {
    throw new Error(`Invalid ${fieldName}: must not be empty.`);
  }
  if (trimmed.length > maxLength) {
    throw new Error(`Invalid ${fieldName}: must not exceed ${maxLength} characters.`);
  }
  return trimmed;
}

